export async function getDebts(customerId) {
  const response = await fetch("https://localhost:7111/api/Debt/customerid?customerId=" + customerId);  

  if (!response.ok) {
    throw new Error("Failed to fetch debts");
  }

  return await response.json();
}

export async function getDebtDetails(id) {
  const response = await fetch("https://localhost:7111/api/Debt/id?id=1" + debtId);  

  if (!response.ok) {
    throw new Error("Failed to fetch debtdetails");
  }

  return await response.json();
}
